firmware_template.source:
#include "lcd_i2c.h"
#include <Wire.h>
static LiquidCrystal_I2C lcd(0x27, 16, 2);
void lcd_setup() {
  Wire.begin();
  lcd.init();
  lcd.backlight();
  lcd.clear();
  Serial.println("[lcd] OK 16x2");
}
void lcd_clear() { lcd.clear(); }
void lcd_print(int row, const char* t) {
  lcd.setCursor(0, constrain(row, 0, 1));
  lcd.print(t);
}
void lcd_print_at(int col, int row, const char* t) {
  lcd.setCursor(col, row); lcd.print(t);
}
void lcd_backlight(bool on) { if (on) lcd.backlight(); else lcd.noBacklight(); }
